CREATE SCHEMA IF NOT EXISTS bucket;

CREATE TABLE IF NOT EXISTS bucket.buckets (
    id UUID NOT NULL DEFAULT gen_random_uuid(),
    name TEXT NOT NULL,
    slug TEXT NOT NULL,
    description TEXT,
    owner_id UUID NOT NULL,
    bucket_type bucket_type NOT NULL DEFAULT 'user',
    status bucket_status NOT NULL DEFAULT 'active',
    storage_backend storage_backend NOT NULL DEFAULT 'local',
    root_path TEXT NOT NULL,
    file_count INTEGER NOT NULL DEFAULT 0,
    total_size_bytes BIGINT NOT NULL DEFAULT 0,
    max_file_size BIGINT,
    allowed_mime_types TEXT[] NOT NULL,
    auto_delete_after_days INTEGER,
    enable_cdn BOOLEAN NOT NULL DEFAULT FALSE,
    enable_versioning BOOLEAN NOT NULL DEFAULT TRUE,
    enable_deduplication BOOLEAN NOT NULL DEFAULT TRUE,
    metadata JSONB NOT NULL DEFAULT '{"created_at":null,"updated_at":null,"deleted_at":null,"created_by":null,"updated_by":null,"deleted_by":null}'::jsonb,
    PRIMARY KEY (id)
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_buckets_slug ON bucket.buckets (slug);

CREATE INDEX IF NOT EXISTS idx_buckets_owner_id ON bucket.buckets (owner_id);

